<?php require_once "../config/database.php"; require_once "../includes/session.php"; requireAdmin(); 
if(isset($_GET['toggle'])){$u=$conn->prepare("SELECT status FROM users WHERE user_id=?");$u->execute([$_GET['toggle']]);$st=$u->fetchColumn();$conn->prepare("UPDATE users SET status=? WHERE user_id=?")->execute([$st=='Active'?'Blocked':'Active',$_GET['toggle']]);}include "../includes/header.php";$rows=$conn->query("SELECT * FROM users ORDER BY user_id DESC")->fetchAll(PDO::FETCH_ASSOC);?><div class="container"><h1 class="section-title">Users</h1><div class="table-wrap"><table><tr><th>Name</th><th>Email</th><th>Role</th><th>Status</th><th>Action</th></tr><?php foreach($rows as $u):?><tr><td><?=e($u['full_name'])?></td><td><?=e($u['email'])?></td><td><?=$u['role']?></td><td><?=$u['status']?></td><td><?php if($u['role']!='admin'):?><a class="btn danger" href="?toggle=<?=$u['user_id']?>">Block/Unblock</a><?php endif;?></td></tr><?php endforeach;?></table></div></div><?php include "../includes/footer.php";?>
